python - <<'PY'
import json
from datetime import datetime, timedelta

src='day08/user_activity_raw.json'
with open(src) as f:
    users=json.load(f)

now=datetime.now()

# Helpers to interpret the human-ish last_login strings relative to 'now'
weekday_map={'monday':0,'tuesday':1,'wednesday':2,'thursday':3,'friday':4,'saturday':5,'sunday':6}

def parse_last_login(s, now):
    s=s.strip().lower()
    if s=='today':
        return now.date()
    if s=='yesterday':
        return (now - timedelta(days=1)).date()
    if s.endswith(' days ago'):
        n=int(s.split(' ')[0])
        return (now - timedelta(days=n)).date()
    if s.endswith(' day ago'):
        n=int(s.split(' ')[0])
        return (now - timedelta(days=n)).date()
    if s.startswith('last '):
        wd=s.replace('last ','').strip()
        if wd not in weekday_map:
            return None
        target=weekday_map[wd]
        # go back to previous occurrence of that weekday (strictly before today if same weekday)
        days_back=(now.weekday()-target) % 7
        if days_back==0:
            days_back=7
        return (now - timedelta(days=days_back)).date()
    if s.endswith(' weeks ago'):
        n=int(s.split(' ')[0])
        return (now - timedelta(days=7*n)).date()
    if s.endswith(' week ago'):
        n=int(s.split(' ')[0])
        return (now - timedelta(days=7*n)).date()
    return None

parsed=[]
active_cutoff=(now - timedelta(days=7)).date()
active=0
session_sum=0

for u in users:
    d=parse_last_login(u['last_login'], now)
    session_sum += u.get('session_count',0)
    is_active = (d is not None and d >= active_cutoff)
    if is_active:
        active += 1
    parsed.append({
        'user_id': u['user_id'],
        'last_login_raw': u['last_login'],
        'last_login_date': d.isoformat() if d else None,
        'session_count': u.get('session_count'),
        'active_days': u.get('active_days'),
        'is_active_7d': is_active
    })

total=len(users)
avg_sessions=round(session_sum/total, 3) if total else 0.0

report={
    'generated_at': now.isoformat(),
    'source_file': src,
    'active_window_days': 7,
    'active_cutoff_date': active_cutoff.isoformat(),
    'summary': {
        'total_users': total,
        'active_users': active,
        'avg_sessions': avg_sessions
    },
    'users': parsed
}

out_path='day08/20260325_user_activity_analysis_report.json'
with open(out_path,'w') as f:
    json.dump(report,f,indent=2)
print('wrote',out_path)
print(json.dumps(report['summary'],indent=2))
PY
